#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <time.h>
#include <unistd.h>
#include <sys/time.h>

#define SIZE 1000.0
#define CUTOFF 2.0
#define CUTOFF2 (CUTOFF*CUTOFF)
#define DT 0.0005
#define T_FINAL 1.0
#define SEED 12345
#define MIN(a,b) ((a)<(b)?(a):(b))
#define MAX(a,b) ((a)>(b)?(a):(b))

