    init_particles(parts, n);
    double sim_time;
    simulate(parts, n, &sim_time, threads);
    printf("n = %d, threads = %d, simulation time = %f seconds\n", n, threads, sim_time);
    validate(parts, n);
    // write output file
    if (!outfile) outfile = "/app/openmp.txt";
    FILE *f = fopen(outfile, "w");
    if (!f) { perror(outfile); exit(1); }
    fprintf(f, "%d %f\n", n, SIZE);
    for (int i = 0; i < n; i++) {
        fprintf(f, "%f %f\n", parts[i].x, parts[i].y);
    }
    fclose(f);
    // write summary file
    if (!sumfile) sumfile = "/app/openmp_summary.txt";
    f = fopen(sumfile, "w");
    if (!f) { perror(sumfile); exit(1); }
    fprintf(f, "%d %d %f\n", n, threads, sim_time);
    fclose(f);
    free(parts);
    return 0;
}
