        MPI_Allgatherv(y_send, local_n, MPI_DOUBLE, all[0].y, recvcounts, displs, MPI_DOUBLE, MPI_COMM_WORLD);
        free(x_send); free(y_send); free(recvcounts); free(displs);
    }
    double end_time = get_wall_time();
    double sim_time = end_time - start_time;
    // validation on rank 0
    if (rank == 0) {
