#include <sys/time.h>
#include <mpi.h>

#define SIZE 1000.0
#define CUTOFF 5.0
#define CUTOFF2 (CUTOFF*CUTOFF)
#define DT 0.005
#define T_FINAL 0.1
#define SEED 12345
#define MIN(a,b) ((a)<(b)?(a):(b))
#define MAX(a,b) ((a)>(b)?(a):(b))

#define GRID_SIZE ((int)ceil(SIZE / CUTOFF))
