        parts[i].ax = 0.0;
        parts[i].ay = 0.0;
    }
}

void compute_forces(Particle *local, int local_n, int start_idx, Particle *global, int n) {
    // reset accelerations for local particles
    for (int i = 0; i < local_n; i++) {
        local[i].ax = 0.0;
        local[i].ay = 0.0;
    }
    // spatial binning using global positions
    Node **grid = calloc(GRID_COUNT, sizeof(Node*));
    Node *nodes = malloc(n * sizeof(Node));
    for (int i = 0; i < n; i++) {
        int cx = (int)(global[i].x / CUTOFF);
        int cy = (int)(global[i].y / CUTOFF);
        int cell = cy * GRID_SIZE + cx;
        nodes[i].idx = i;
        nodes[i].next = grid[cell];
        grid[cell] = &nodes[i];
    }
    // compute forces for local particles
    for (int li = 0; li < local_n; li++) {
        int gi = start_idx + li;
        int cx = (int)(global[gi].x / CUTOFF);
        int cy = (int)(global[gi].y / CUTOFF);
        for (int dy = -1; dy <= 1; dy++) {
            int ncy = cy + dy;
            if (ncy < 0 || ncy >= GRID_SIZE) continue;
            for (int dx = -1; dx <= 1; dx++) {
                int ncx = cx + dx;
                if (ncx < 0 || ncx >= GRID_SIZE) continue;
                int cell = ncy * GRID_SIZE + ncx;
                Node *node = grid[cell];
                while (node) {
                    int gj = node->idx;
                    if (gi < gj) { // each pair once
                        double dxp = global[gi].x - global[gj].x;
                        double dyp = global[gi].y - global[gj].y;
                        double dist2 = dxp*dxp + dyp*dyp;
                        if (dist2 > CUTOFF2) { node = node->next; continue; }
                        if (dist2 == 0.0) dist2 = 1e-12;
                        double dist = sqrt(dist2);
                        double force = (CUTOFF - dist) / (dist * CUTOFF);
                        double fx = force * dxp / dist;
                        double fy = force * dyp / dist;
                        local[li].ax += fx;
                        local[li].ay += fy;
                        // acceleration for particle gj will be updated by its owning rank
                    }
                    node = node->next;
                }
            }
        }
    }
    free(nodes);
    free(grid);
}

void update(Particle *local, int local_n, Particle *global, int start_idx) {
    for (int li = 0; li < local_n; li++) {
        int gi = start_idx + li;
        local[li].vx += local[li].ax * DT;
        local[li].vy += local[li].ay * DT;
        local[li].x += local[li].vx * DT;
        local[li].y += local[li].vy * DT;
        // bounce off walls
        if (local[li].x < 0) { local[li].x = -local[li].x; local[li].vx = -local[li].vx; }
        if (local[li].x > SIZE) { local[li].x = 2*SIZE - local[li].x; local[li].vx = -local[li].vx; }
        if (local[li].y < 0) { local[li].y = -local[li].y; local[li].vy = -local[li].vy; }
        if (local[li].y > SIZE) { local[li].y = 2*SIZE - local[li].y; local[li].vy = -local[li].vy; }
        // copy back to global array (for gathering)
        global[gi].x = local[li].x;
        global[gi].y = local[li].y;
        global[gi].vx = local[li].vx;
        global[gi].vy = local[li].vy;
    }
}

int main(int argc, char **argv) {
    MPI_Init(&argc, &argv);
    int rank, size;
    MPI_Comm_rank(MPI_COMM_WORLD, &rank);
