    int n = 0;
    char *outfile = NULL;
    char *sumfile = NULL;
    if (rank == 0) {
        int c;
        while ((c = getopt(argc, argv, "n:o:s:")) != -1) {
            switch (c) {
                case 'n': n = atoi(optarg); break;
                case 'o': outfile = optarg; break;
                case 's': sumfile = optarg; break;
                default: fprintf(stderr, "Usage: %s -n <particles> [-o output] [-s summary]\n", argv[0]); exit(1);
            }
        }
        if (n <= 0) {
            fprintf(stderr, "Particle count must be positive\n");
            MPI_Abort(MPI_COMM_WORLD, 1);
        }
    }
    MPI_Bcast(&n, 1, MPI_INT, 0, MPI_COMM_WORLD);
    // allocate global array (replicated, will be kept in sync via Allgather)
    Particle *global = malloc(n * sizeof(Particle));
    init_particles(global, n); // each rank initializes same
    // determine local range
    int chunk = n / size;
    int remainder = n % size;
    int start = rank * chunk + (rank < remainder ? rank : remainder);
    int end = start + chunk + (rank < remainder ? 1 : 0);
    int local_n = end - start;
    Particle *local = malloc(local_n * sizeof(Particle));
    // copy initial local data
    for (int i = 0; i < local_n; i++) {
        local[i] = global[start + i];
    }
    double start_time = get_wall_time();
    int steps = (int)ceil(T_FINAL / DT);
    for (int step = 0; step < steps; step++) {
        // gather positions (x,y) from all ranks to global
        double *xbuf = malloc(n * sizeof(double));
        double *ybuf = malloc(n * sizeof(double));
        for (int i = 0; i < local_n; i++) {
            xbuf[start + i] = local[i].x;
            ybuf[start + i] = local[i].y;
        }
        MPI_Allgather(MPI_IN_PLACE, 0, MPI_DATATYPE_NULL, xbuf, local_n, MPI_DOUBLE, MPI_COMM_WORLD);
        MPI_Allgather(MPI_IN_PLACE, 0, MPI_DATATYPE_NULL, ybuf, local_n, MPI_DOUBLE, MPI_COMM_WORLD);
        // copy back to global
        for (int i = 0; i < n; i++) {
            global[i].x = xbuf[i];
            global[i].y = ybuf[i];
        }
        free(xbuf); free(ybuf);
        // compute forces for local particles
        compute_forces(local, local_n, start, global, n);
        // update local particles and copy positions back to global
        update(local, local_n, global, start);
    }
    double end_time = get_wall_time();
    double sim_time = end_time - start_time;
    // gather final positions to rank 0 for output
    double *x_final = NULL;
    double *y_final = NULL;
    if (rank == 0) {
        x_final = malloc(n * sizeof(double));
        y_final = malloc(n * sizeof(double));
    }
    // each rank sends its local x and y
    double *x_send = malloc(local_n * sizeof(double));
    double *y_send = malloc(local_n * sizeof(double));
    for (int i = 0; i < local_n; i++) {
        x_send[i] = local[i].x;
        y_send[i] = local[i].y;
    }
    int *recvcounts = malloc(size * sizeof(int));
    int *displs = malloc(size * sizeof(int));
    for (int r = 0; r < size; r++) {
        int r_chunk = n / size;
        int r_rem = n % size;
        recvcounts[r] = r_chunk + (r < r_rem ? 1 : 0);
        displs[r] = (r == 0) ? 0 : displs[r-1] + recvcounts[r-1];
    }
    MPI_Gatherv(x_send, local_n, MPI_DOUBLE, x_final, recvcounts, displs, MPI_DOUBLE, 0, MPI_COMM_WORLD);
    MPI_Gatherv(y_send, local_n, MPI_DOUBLE, y_final, recvcounts, displs, MPI_DOUBLE, 0, MPI_COMM_WORLD);
    free(x_send); free(y_send); free(recvcounts); free(displs);
    if (rank == 0) {
        // compute validation
        double absmin = 1e100;
        double absavg = 0.0;
        int count = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i+1; j < n; j++) {
                double dx = x_final[i] - x_final[j];
                double dy = y_final[i] - y_final[j];
                double dist = sqrt(dx*dx + dy*dy);
                double normalized = dist / CUTOFF;
                if (normalized < absmin) absmin = normalized;
                absavg += normalized;
                count++;
            }
        }
        if (count > 0) absavg /= count;
        printf("n = %d, procs = %d, simulation time = %f seconds\n", n, size, sim_time);
        printf("absmin = %f\n", absmin);
        printf("absavg = %f\n", absavg);
        // write output file
        if (!outfile) outfile = "/app/mpi.txt";
        FILE *f = fopen(outfile, "w");
        fprintf(f, "%d %f\n", n, SIZE);
        for (int i = 0; i < n; i++) fprintf(f, "%f %f\n", x_final[i], y_final[i]);
        fclose(f);
        // write summary file
        if (!sumfile) sumfile = "/app/mpi_summary.txt";
        f = fopen(sumfile, "w");
        fprintf(f, "%d %d %f\n", n, size, sim_time);
        fclose(f);
        free(x_final); free(y_final);
    }
    free(global); free(local);
    MPI_Finalize();
    return 0;
}
