      "keystrokes": "cat > mpi.c << 'EOF'
#define _POSIX_C_SOURCE 2
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <time.h>
#include <unistd.h>
#include <sys/time.h>
#include <mpi.h>

#define SIZE 1000.0
#define CUTOFF 5.0
#define CUTOFF2 (CUTOFF*CUTOFF)
#define DT 0.005
#define T_FINAL 0.1
#define SEED 12345
#define MIN(a,b) ((a)<(b)?(a):(b))
#define MAX(a,b) ((a)>(b)?(a):(b))

#define GRID_SIZE ((int)ceil(SIZE / CUTOFF))
#define GRID_COUNT (GRID_SIZE * GRID_SIZE)

typedef struct {
    double x, y;
    double vx, vy;
    double ax, ay;
} Particle;

typedef struct Node {
    int idx;
    struct Node *next;
} Node;

static double get_wall_time() {
    struct timeval time;
    gettimeofday(&time, NULL);
    return (double)time.tv_sec + (double)time.tv_usec * 1e-6;
}

void init_particles(Particle *parts, int n) {
    srand(SEED);
    for (int i = 0; i < n; i++) {
        parts[i].x = (rand() / (double)RAND_MAX) * SIZE;
        parts[i].y = (rand() / (double)RAND_MAX) * SIZE;
        parts[i].vx = (rand() / (double)RAND_MAX) - 0.5;
        parts[i].vy = (rand() / (double)RAND_MAX) - 0.5;
        parts[i].ax = 0.0;
        parts[i].ay = 0.0;
    }
}

void compute_forces(Particle *parts, int n) {
    // reset accelerations
    for (int i = 0; i < n; i++) {
        parts[i].ax = 0.0;
        parts[i].ay = 0.0;
    }
    // spatial binning
    Node **grid = calloc(GRID_COUNT, sizeof(Node*));
    Node *nodes = malloc(n * sizeof(Node));
    for (int i = 0; i < n; i++) {
        int cx = (int)(parts[i].x / CUTOFF);
        int cy = (int)(parts[i].y / CUTOFF);
        int cell = cy * GRID_SIZE + cx;
        nodes[i].idx = i;
        nodes[i].next = grid[cell];
        grid[cell] = &nodes[i];
    }
    for (int cy = 0; cy < GRID_SIZE; cy++) {
        for (int cx = 0; cx < GRID_SIZE; cx++) {
            int cell = cy * GRID_SIZE + cx;
            Node *node = grid[cell];
            while (node) {
                int i = node->idx;
                for (int dy = -1; dy <= 1; dy++) {
                    int ncy = cy + dy;
                    if (ncy < 0 || ncy >= GRID_SIZE) continue;
                    for (int dx = -1; dx <= 1; dx++) {
                        int ncx = cx + dx;
                        if (ncx < 0 || ncx >= GRID_SIZE) continue;
                        int ncell = ncy * GRID_SIZE + ncx;
                        Node *node2 = grid[ncell];
                        while (node2) {
                            int j = node2->idx;
                            if (i < j) {
                                double dxp = parts[i].x - parts[j].x;
                                double dyp = parts[i].y - parts[j].y;
                                double dist2 = dxp*dxp + dyp*dyp;
                                if (dist2 > CUTOFF2) { node2 = node2->next; continue; }
                                if (dist2 == 0.0) dist2 = 1e-12;
                                double dist = sqrt(dist2);
                                double force = (CUTOFF - dist) / (dist * CUTOFF);
                                double fx = force * dxp / dist;
                                double fy = force * dyp / dist;
                                parts[i].ax += fx;
                                parts[i].ay += fy;
                                parts[j].ax -= fx;
                                parts[j].ay -= fy;
                            }
                            node2 = node2->next;
                        }
                    }
                }
                node = node->next;
            }
        }
    }
    free(nodes);
    free(grid);
}

void update(Particle *parts, int n) {
    for (int i = 0; i < n; i++) {
        parts[i].vx += parts[i].ax * DT;
        parts[i].vy += parts[i].ay * DT;
        parts[i].x += parts[i].vx * DT;
        parts[i].y += parts[i].vy * DT;
        if (parts[i].x < 0) { parts[i].x = -parts[i].x; parts[i].vx = -parts[i].vx; }
        if (parts[i].x > SIZE) { parts[i].x = 2*SIZE - parts[i].x; parts[i].vx = -parts[i].vx; }
        if (parts[i].y < 0) { parts[i].y = -parts[i].y; parts[i].vy = -parts[i].vy; }
        if (parts[i].y > SIZE) { parts[i].y = 2*SIZE - parts[i].y; parts[i].vy = -parts[i].vy; }
    }
}

void validate(Particle *parts, int n, double *absmin, double *absavg) {
    *absmin = 1e100;
    *absavg = 0.0;
    int count = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i+1; j < n; j++) {
            double dx = parts[i].x - parts[j].x;
            double dy = parts[i].y - parts[j].y;
            double dist = sqrt(dx*dx + dy*dy);
            double normalized = dist / CUTOFF;
            if (normalized < *absmin) *absmin = normalized;
            *absavg += normalized;
            count++;
        }
    }
    if (count > 0) *absavg /= count;
}

int main(int argc, char **argv) {
    MPI_Init(&argc, &argv);
    int rank, size;
    MPI_Comm_rank(MPI_COMM_WORLD, &rank);
    MPI_Comm_size(MPI_COMM_WORLD, &size);
    int n = 0;
    char *outfile = NULL;
    char *sumfile = NULL;
    if (rank == 0) {
        int c;
        while ((c = getopt(argc, argv, "n:o:s:")) != -1) {
            switch (c) {
                case 'n': n = atoi(optarg); break;
                case 'o': outfile = optarg; break;
                case 's': sumfile = optarg; break;
                default: fprintf(stderr, "Usage: %s -n <particles> [-o output] [-s summary]\n", argv[0]); exit(1);
            }
        }
        if (n <= 0) {
            fprintf(stderr, "Particle count must be positive\n");
            MPI_Abort(MPI_COMM_WORLD, 1);
        }
    }
    MPI_Bcast(&n, 1, MPI_INT, 0, MPI_COMM_WORLD);
    Particle *parts = NULL;
    double *init_x = NULL;
    double *init_y = NULL;
    if (rank == 0) {
        parts = malloc(n * sizeof(Particle));
        init_particles(parts, n);
        init_x = malloc(n * sizeof(double));
        init_y = malloc(n * sizeof(double));
        for (int i = 0; i < n; i++) {
            init_x[i] = parts[i].x;
            init_y[i] = parts[i].y;
        }
    } else {
        parts = malloc(1 * sizeof(Particle)); // dummy
    }
    double start = get_wall_time();
    int steps = (int)ceil(T_FINAL / DT);
    if (rank == 0) {
        for (int step = 0; step < steps; step++) {
            compute_forces(parts, n);
            update(parts, n);
        }
    }
    double end = get_wall_time();
    double sim_time = end - start;
    // broadcast sim_time? Not needed.
    if (rank == 0) {
        double absmin, absavg;
        validate(parts, n, &absmin, &absavg);
        printf("n = %d, procs = %d, simulation time = %f seconds\n", n, size, sim_time);
        printf("absmin = %f\n", absmin);
        printf("absavg = %f\n", absavg);
        // movement
        int moved = 0;
        double eps = 1e-6;
        for (int i = 0; i < n; i++) {
            if (fabs(parts[i].x - init_x[i]) > eps || fabs(parts[i].y - init_y[i]) > eps) moved++;
        }
        printf("moved = %d/%d (%f%%)\n", moved, n, 100.0*moved/n);
        free(init_x); free(init_y);
        // write output file
        if (!outfile) outfile = "/app/mpi.txt";
        FILE *f = fopen(outfile, "w");
        fprintf(f, "%d %f\n", n, SIZE);
        for (int i = 0; i < n; i++) fprintf(f, "%f %f\n", parts[i].x, parts[i].y);
        fclose(f);
        // write summary file
        if (!sumfile) sumfile = "/app/mpi_summary.txt";
        f = fopen(sumfile, "w");
        fprintf(f, "%d %d %f\n", n, size, sim_time);
        fclose(f);
    }
    free(parts);
    MPI_Finalize();
    return 0;
}
